use std::arch::x86_64::*;

/// Compute L2 squared distance using AVX-512 for 128-dim f32 vectors.
/// Returns f64 for the API but internally uses f32 accumulation for speed.
#[inline(always)]
pub fn l2_distance(a: &[f32], b: &[f32]) -> f64 {
    debug_assert_eq!(a.len(), 128);
    debug_assert_eq!(b.len(), 128);
    l2_distance_avx512(a, b) as f64
}

#[inline(always)]
pub fn l2_distance_f32(a: &[f32], b: &[f32]) -> f32 {
    debug_assert_eq!(a.len(), 128);
    debug_assert_eq!(b.len(), 128);
    l2_distance_avx512(a, b)
}

#[cfg(target_arch = "x86_64")]
#[inline(always)]
fn l2_distance_avx512(a: &[f32], b: &[f32]) -> f32 {
    unsafe {
        if is_x86_feature_detected!("avx512f") {
            l2_distance_avx512_impl(a, b)
        } else if is_x86_feature_detected!("avx2") {
            l2_distance_avx2_impl(a, b)
        } else {
            l2_distance_scalar(a, b)
        }
    }
}

#[cfg(not(target_arch = "x86_64"))]
#[inline(always)]
fn l2_distance_avx512(a: &[f32], b: &[f32]) -> f32 {
    l2_distance_scalar(a, b)
}

#[cfg(target_arch = "x86_64")]
#[target_feature(enable = "avx512f")]
#[inline]
unsafe fn l2_distance_avx512_impl(a: &[f32], b: &[f32]) -> f32 {
    let ap = a.as_ptr();
    let bp = b.as_ptr();

    // 128 floats = 8 x 16-float AVX-512 registers
    let mut sum = _mm512_setzero_ps();

    // Unroll 8 iterations of 16 floats each
    let mut i = 0usize;
    while i < 128 {
        let va = _mm512_loadu_ps(ap.add(i));
        let vb = _mm512_loadu_ps(bp.add(i));
        let diff = _mm512_sub_ps(va, vb);
        sum = _mm512_fmadd_ps(diff, diff, sum);
        i += 16;
    }

    _mm512_reduce_add_ps(sum)
}

#[cfg(target_arch = "x86_64")]
#[target_feature(enable = "avx2", enable = "fma")]
#[inline]
unsafe fn l2_distance_avx2_impl(a: &[f32], b: &[f32]) -> f32 {
    let ap = a.as_ptr();
    let bp = b.as_ptr();

    let mut sum0 = _mm256_setzero_ps();
    let mut sum1 = _mm256_setzero_ps();

    let mut i = 0usize;
    while i < 128 {
        let va0 = _mm256_loadu_ps(ap.add(i));
        let vb0 = _mm256_loadu_ps(bp.add(i));
        let diff0 = _mm256_sub_ps(va0, vb0);
        sum0 = _mm256_fmadd_ps(diff0, diff0, sum0);

        let va1 = _mm256_loadu_ps(ap.add(i + 8));
        let vb1 = _mm256_loadu_ps(bp.add(i + 8));
        let diff1 = _mm256_sub_ps(va1, vb1);
        sum1 = _mm256_fmadd_ps(diff1, diff1, sum1);

        i += 16;
    }

    sum0 = _mm256_add_ps(sum0, sum1);

    // Horizontal sum
    let hi = _mm256_extractf128_ps(sum0, 1);
    let lo = _mm256_castps256_ps128(sum0);
    let sum128 = _mm_add_ps(lo, hi);
    let shuf = _mm_movehdup_ps(sum128);
    let sums = _mm_add_ps(sum128, shuf);
    let shuf2 = _mm_movehl_ps(sums, sums);
    let result = _mm_add_ss(sums, shuf2);
    _mm_cvtss_f32(result)
}

fn l2_distance_scalar(a: &[f32], b: &[f32]) -> f32 {
    a.iter()
        .zip(b.iter())
        .map(|(&x, &y)| {
            let d = x - y;
            d * d
        })
        .sum()
}

/// Batch compute L2 distances from a single query to many stored vectors.
/// Vectors are stored contiguously in `data` with stride `dim`.
/// Results written to `distances`.
#[inline]
pub fn l2_distances_batch(query: &[f32], data: &[f32], dim: usize, count: usize, distances: &mut [f32]) {
    debug_assert_eq!(dim, 128);
    debug_assert!(data.len() >= count * dim);
    debug_assert!(distances.len() >= count);

    for i in 0..count {
        let offset = i * dim;
        distances[i] = l2_distance_f32(query, &data[offset..offset + dim]);
    }
}
"}

{"path": "src/db.rs", "content": "use crate::api::*;
use crate::distance::{l2_distance_f32, l2_distances_batch};
use parking_lot::RwLock;
use rayon::prelude::*;
use std::sync::atomic::{AtomicBool, AtomicUsize, Ordering};

const DIM: usize = 128;
const NUM_CLUSTERS: usize = 256;
const NPROBE: usize = 16;
const KMEANS_ITERS: usize = 10;
const KMEANS_SAMPLE_SIZE: usize = 50_000;
const BUILD_THRESHOLD: usize = 100_000;

pub struct VectorDB {
    // Flat storage: all vectors stored contiguously
    vectors: RwLock<Vec<f32>>,  // DIM floats per vector
    ids: RwLock<Vec<u64>>,
    count: AtomicUsize,

    // IVF index
    index: RwLock<Option<IVFIndex>>,
    index_built: AtomicBool,
    building_index: AtomicBool,
}

struct IVFIndex {
    centroids: Vec<f32>,     // NUM_CLUSTERS * DIM
    // For each cluster: vector indices (into the flat storage)
    cluster_indices: Vec<Vec<u32>>,
    // For each cluster: contiguous vector data for cache-friendly access
    cluster_data: Vec<Vec<f32>>,
    // Snapshot of how many vectors were indexed
    indexed_count: usize,
}

impl VectorDB {
    pub fn new() -> Self {
        // Initialize rayon with 4 threads to match pinned cores
        rayon::ThreadPoolBuilder::new()
            .num_threads(4)
            .build_global()
            .ok();

        VectorDB {
            vectors: RwLock::new(Vec::new()),
            ids: RwLock::new(Vec::new()),
            count: AtomicUsize::new(0),
            index: RwLock::new(None),
            index_built: AtomicBool::new(false),
            building_index: AtomicBool::new(false),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        debug_assert_eq!(vector.len(), DIM);
        let mut vecs = self.vectors.write();
        let mut ids = self.ids.write();
        vecs.extend_from_slice(&vector);
        ids.push(id);
        self.count.fetch_add(1, Ordering::Release);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let n = vectors.len();
        {
            let mut vecs = self.vectors.write();
            let mut ids = self.ids.write();
            vecs.reserve(n * DIM);
            ids.reserve(n);
            for (id, vector) in &vectors {
                debug_assert_eq!(vector.len(), DIM);
                vecs.extend_from_slice(vector);
                ids.push(*id);
            }
        }
        self.count.fetch_add(n, Ordering::Release);

        // Check if we should build the index
        let total = self.count.load(Ordering::Acquire);
        if total >= BUILD_THRESHOLD && !self.index_built.load(Ordering::Acquire) {
            if !self.building_index.swap(true, Ordering::AcqRel) {
                self.build_ivf_index();
                self.index_built.store(true, Ordering::Release);
            }
        }

        n
    }

    fn build_ivf_index(&self) {
        let vecs = self.vectors.read();
        let ids_guard = self.ids.read();
        let n = ids_guard.len();

        if n == 0 { return; }

        // Step 1: K-means clustering
        let centroids = self.kmeans_clustering(&vecs, n);

        // Step 2: Assign each vector to nearest centroid
        let mut cluster_indices: Vec<Vec<u32>> = vec![Vec::new(); NUM_CLUSTERS];

        // Parallel assignment
        let assignments: Vec<usize> = (0..n).into_par_iter().map(|i| {
            let vec_data = &vecs[i * DIM..(i + 1) * DIM];
            find_nearest_centroid(vec_data, &centroids)
        }).collect();

        for (i, &cluster_id) in assignments.iter().enumerate() {
            cluster_indices[cluster_id].push(i as u32);
        }

        // Step 3: Build contiguous cluster data for cache-friendly access
        let cluster_data: Vec<Vec<f32>> = cluster_indices.iter().map(|indices| {
            let mut data = Vec::with_capacity(indices.len() * DIM);
            for &idx in indices {
                let offset = idx as usize * DIM;
                data.extend_from_slice(&vecs[offset..offset + DIM]);
            }
            data
        }).collect();

        let index = IVFIndex {
            centroids,
            cluster_indices,
            cluster_data,
            indexed_count: n,
        };

        *self.index.write() = Some(index);
    }

    fn kmeans_clustering(&self, vecs: &[f32], n: usize) -> Vec<f32> {
        // Sample a subset for k-means
        let sample_size = n.min(KMEANS_SAMPLE_SIZE);

        // Deterministic sampling: take evenly spaced vectors
        let step = if sample_size < n { n / sample_size } else { 1 };
        let sample_indices: Vec<usize> = (0..sample_size).map(|i| i * step).collect();

        // Initialize centroids: pick first NUM_CLUSTERS samples
        let mut centroids = vec![0.0f32; NUM_CLUSTERS * DIM];
        let centroid_step = sample_size.max(NUM_CLUSTERS) / NUM_CLUSTERS;
        for c in 0..NUM_CLUSTERS {
            let src_idx = sample_indices[c * centroid_step % sample_size];
            let src_offset = src_idx * DIM;
            centroids[c * DIM..(c + 1) * DIM].copy_from_slice(&vecs[src_offset..src_offset + DIM]);
        }

        // K-means iterations
        for _iter in 0..KMEANS_ITERS {
            // Assign samples to clusters (parallel)
            let assignments: Vec<usize> = sample_indices.par_iter().map(|&idx| {
                let vec_data = &vecs[idx * DIM..(idx + 1) * DIM];
                find_nearest_centroid(vec_data, &centroids)
            }).collect();

            // Recompute centroids
            let mut new_centroids = vec![0.0f64; NUM_CLUSTERS * DIM];
            let mut counts = vec![0usize; NUM_CLUSTERS];

            for (si, &cluster_id) in assignments.iter().enumerate() {
                let src_idx = sample_indices[si];
                let src_offset = src_idx * DIM;
                counts[cluster_id] += 1;
                for d in 0..DIM {
                    new_centroids[cluster_id * DIM + d] += vecs[src_offset + d] as f64;
                }
            }

            for c in 0..NUM_CLUSTERS {
                if counts[c] > 0 {
                    let inv = 1.0 / counts[c] as f64;
                    for d in 0..DIM {
                        centroids[c * DIM + d] = (new_centroids[c * DIM + d] * inv) as f32;
                    }
                }
            }
        }

        centroids
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let top_k = top_k as usize;

        // Try IVF search first
        if self.index_built.load(Ordering::Acquire) {
            let index_guard = self.index.read();
            if let Some(ref index) = *index_guard {
                return self.ivf_search(vector, top_k, index);
            }
        }

        // Fallback to brute-force
        self.brute_force_search(vector, top_k)
    }

    fn ivf_search(&self, query: &[f32], top_k: usize, index: &IVFIndex) -> Vec<SearchResult> {
        let ids_guard = self.ids.read();

        // Find NPROBE nearest centroids
        let mut centroid_dists: Vec<(usize, f32)> = (0..NUM_CLUSTERS)
            .map(|c| {
                let centroid = &index.centroids[c * DIM..(c + 1) * DIM];
                (c, l2_distance_f32(query, centroid))
            })
            .collect();

        // Partial sort to find top NPROBE centroids
        centroid_dists.select_nth_unstable_by(NPROBE - 1, |a, b| a.1.partial_cmp(&b.1).unwrap());
        centroid_dists.truncate(NPROBE);

        // Search within selected clusters using a max-heap (BinaryHeap) for top-k
        let mut heap: Vec<(f32, u64)> = Vec::with_capacity(top_k + 1);
        let mut worst = f32::INFINITY;

        for &(cluster_id, _) in &centroid_dists {
            let cluster_vecs = &index.cluster_data[cluster_id];
            let cluster_ids = &index.cluster_indices[cluster_id];
            let cluster_count = cluster_ids.len();

            if cluster_count == 0 { continue; }

            // Process vectors in this cluster
            let mut dists_buf = vec![0.0f32; cluster_count];
            l2_distances_batch(query, cluster_vecs, DIM, cluster_count, &mut dists_buf);

            for (j, &dist) in dists_buf.iter().enumerate() {
                if dist < worst || heap.len() < top_k {
                    let id = ids_guard[cluster_ids[j] as usize];
                    if heap.len() < top_k {
                        heap.push((dist, id));
                        if heap.len() == top_k {
                            // Build max-heap: find worst
                            worst = heap.iter().map(|x| x.0).fold(f32::NEG_INFINITY, f32::max);
                        }
                    } else {
                        // Replace worst element
                        let worst_idx = heap.iter().enumerate()
                            .max_by(|a, b| a.1.0.partial_cmp(&b.1.0).unwrap())
                            .unwrap().0;
                        heap[worst_idx] = (dist, id);
                        worst = heap.iter().map(|x| x.0).fold(f32::NEG_INFINITY, f32::max);
                    }
                }
            }
        }

        // Sort by distance
        heap.sort_by(|a, b| a.0.partial_cmp(&b.0).unwrap());

        heap.iter().map(|&(dist, id)| SearchResult {
            id,
            distance: dist as f64,
        }).collect()
    }

    fn brute_force_search(&self, query: &[f32], top_k: usize) -> Vec<SearchResult> {
        let vecs = self.vectors.read();
        let ids_guard = self.ids.read();
        let n = ids_guard.len();

        if n == 0 {
            return Vec::new();
        }

        // Compute all distances in parallel chunks
        let chunk_size = (n + 3) / 4;
        let results: Vec<Vec<(f32, u64)>> = (0..4).into_par_iter().map(|t| {
            let start = t * chunk_size;
            let end = n.min(start + chunk_size);
            if start >= n { return Vec::new(); }

            let count = end - start;
            let mut local_heap: Vec<(f32, u64)> = Vec::with_capacity(top_k + 1);
            let mut worst = f32::INFINITY;

            for i in start..end {
                let dist = l2_distance_f32(query, &vecs[i * DIM..(i + 1) * DIM]);
                if local_heap.len() < top_k || dist < worst {
                    let id = ids_guard[i];
                    if local_heap.len() < top_k {
                        local_heap.push((dist, id));
                        if local_heap.len() == top_k {
                            worst = local_heap.iter().map(|x| x.0).fold(f32::NEG_INFINITY, f32::max);
                        }
                    } else {
                        let worst_idx = local_heap.iter().enumerate()
                            .max_by(|a, b| a.1.0.partial_cmp(&b.1.0).unwrap())
                            .unwrap().0;
                        local_heap[worst_idx] = (dist, id);
                        worst = local_heap.iter().map(|x| x.0).fold(f32::NEG_INFINITY, f32::max);
                    }
                }
            }
            local_heap
        }).collect();

        // Merge results
        let mut merged: Vec<(f32, u64)> = results.into_iter().flatten().collect();
        merged.sort_by(|a, b| a.0.partial_cmp(&b.0).unwrap());
        merged.truncate(top_k);

        merged.iter().map(|&(dist, id)| SearchResult {
            id,
            distance: dist as f64,
        }).collect()
    }
}

#[inline]
fn find_nearest_centroid(vec: &[f32], centroids: &[f32]) -> usize {
    let mut best_idx = 0;
    let mut best_dist = f32::INFINITY;
    for c in 0..NUM_CLUSTERS {
        let centroid = &centroids[c * DIM..(c + 1) * DIM];
        let dist = l2_distance_f32(vec, centroid);
        if dist < best_dist {
            best_dist = dist;
            best_idx = c;
        }
    }
    best_idx
}
"}

{"path": "src/db.rs", "content": "use crate::api::*;
use crate::distance::l2_distance_f32;
use parking_lot::RwLock;
use rayon::prelude::*;
use std::sync::atomic::{AtomicBool, AtomicUsize, Ordering};

const DIM: usize = 128;
const NUM_CLUSTERS: usize = 1024;
const NPROBE: usize = 64;
const KMEANS_ITERS: usize = 12;
const KMEANS_SAMPLE_SIZE: usize = 80_000;
const BUILD_THRESHOLD: usize = 100_000;

pub struct VectorDB {
    // Flat storage: all vectors stored contiguously
    vectors: RwLock<Vec<f32>>,  // DIM floats per vector
    ids: RwLock<Vec<u64>>,
    count: AtomicUsize,

    // IVF index
    index: RwLock<Option<IVFIndex>>,
    index_built: AtomicBool,
    building_index: AtomicBool,
}

struct IVFIndex {
    centroids: Vec<f32>,     // NUM_CLUSTERS * DIM
    // For each cluster: vector IDs
    cluster_ids: Vec<Vec<u64>>,
    // For each cluster: contiguous vector data for cache-friendly access
    cluster_data: Vec<Vec<f32>>,
}

impl VectorDB {
    pub fn new() -> Self {
        // Initialize rayon with 4 threads to match pinned cores
        rayon::ThreadPoolBuilder::new()
            .num_threads(4)
            .build_global()
            .ok();

        VectorDB {
            vectors: RwLock::new(Vec::new()),
            ids: RwLock::new(Vec::new()),
            count: AtomicUsize::new(0),
            index: RwLock::new(None),
            index_built: AtomicBool::new(false),
            building_index: AtomicBool::new(false),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        debug_assert_eq!(vector.len(), DIM);
        let mut vecs = self.vectors.write();
        let mut ids = self.ids.write();
        vecs.extend_from_slice(&vector);
        ids.push(id);
        self.count.fetch_add(1, Ordering::Release);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let n = vectors.len();
        {
            let mut vecs = self.vectors.write();
            let mut ids = self.ids.write();
            vecs.reserve(n * DIM);
            ids.reserve(n);
            for (id, vector) in &vectors {
                debug_assert_eq!(vector.len(), DIM);
                vecs.extend_from_slice(vector);
                ids.push(*id);
            }
        }
        self.count.fetch_add(n, Ordering::Release);

        // Check if we should build the index
        let total = self.count.load(Ordering::Acquire);
        if total >= BUILD_THRESHOLD && !self.index_built.load(Ordering::Acquire) {
            if !self.building_index.swap(true, Ordering::AcqRel) {
                self.build_ivf_index();
                self.index_built.store(true, Ordering::Release);
            }
        }

        n
    }

    fn build_ivf_index(&self) {
        let vecs = self.vectors.read();
        let ids_guard = self.ids.read();
        let n = ids_guard.len();

        if n == 0 { return; }

        // Step 1: K-means clustering
        let centroids = self.kmeans_clustering(&vecs, n);

        // Step 2: Assign each vector to nearest centroid
        let assignments: Vec<usize> = (0..n).into_par_iter().map(|i| {
            let vec_data = &vecs[i * DIM..(i + 1) * DIM];
            find_nearest_centroid(vec_data, &centroids, NUM_CLUSTERS)
        }).collect();

        // Step 3: Build cluster data structures
        let mut cluster_ids_vec: Vec<Vec<u64>> = vec![Vec::new(); NUM_CLUSTERS];
        let mut cluster_data_vec: Vec<Vec<f32>> = vec![Vec::new(); NUM_CLUSTERS];

        for (i, &cluster_id) in assignments.iter().enumerate() {
            cluster_ids_vec[cluster_id].push(ids_guard[i]);
            cluster_data_vec[cluster_id].extend_from_slice(&vecs[i * DIM..(i + 1) * DIM]);
        }

        let index = IVFIndex {
            centroids,
            cluster_ids: cluster_ids_vec,
            cluster_data: cluster_data_vec,
        };

        *self.index.write() = Some(index);
    }

    fn kmeans_clustering(&self, vecs: &[f32], n: usize) -> Vec<f32> {
        let sample_size = n.min(KMEANS_SAMPLE_SIZE);

        // Deterministic sampling: take evenly spaced vectors
        let step = if sample_size < n { n / sample_size } else { 1 };
        let sample_indices: Vec<usize> = (0..sample_size).map(|i| (i * step).min(n - 1)).collect();

        // Build contiguous sample data for faster access
        let mut sample_data = vec![0.0f32; sample_size * DIM];
        for (si, &idx) in sample_indices.iter().enumerate() {
            sample_data[si * DIM..(si + 1) * DIM].copy_from_slice(&vecs[idx * DIM..(idx + 1) * DIM]);
        }

        // Initialize centroids: pick evenly spaced from samples
        let mut centroids = vec![0.0f32; NUM_CLUSTERS * DIM];
        let centroid_step = sample_size / NUM_CLUSTERS;
        for c in 0..NUM_CLUSTERS {
            let src = c * centroid_step;
            centroids[c * DIM..(c + 1) * DIM].copy_from_slice(&sample_data[src * DIM..(src + 1) * DIM]);
        }

        // K-means iterations
        for _iter in 0..KMEANS_ITERS {
            // Assign samples to clusters (parallel)
            let assignments: Vec<usize> = (0..sample_size).into_par_iter().map(|si| {
                let vec_data = &sample_data[si * DIM..(si + 1) * DIM];
                find_nearest_centroid(vec_data, &centroids, NUM_CLUSTERS)
            }).collect();

            // Recompute centroids
            let mut new_centroids = vec![0.0f64; NUM_CLUSTERS * DIM];
            let mut counts = vec![0usize; NUM_CLUSTERS];

            for (si, &cluster_id) in assignments.iter().enumerate() {
                counts[cluster_id] += 1;
                let src_offset = si * DIM;
                for d in 0..DIM {
                    new_centroids[cluster_id * DIM + d] += sample_data[src_offset + d] as f64;
                }
            }

            for c in 0..NUM_CLUSTERS {
                if counts[c] > 0 {
                    let inv = 1.0 / counts[c] as f64;
                    for d in 0..DIM {
                        centroids[c * DIM + d] = (new_centroids[c * DIM + d] * inv) as f32;
                    }
                }
                // If empty cluster, keep previous centroid
            }
        }

        centroids
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let top_k = top_k as usize;

        // Try IVF search first
        if self.index_built.load(Ordering::Acquire) {
            let index_guard = self.index.read();
            if let Some(ref index) = *index_guard {
                return self.ivf_search(vector, top_k, index);
            }
        }

        // Fallback to brute-force
        self.brute_force_search(vector, top_k)
    }

    fn ivf_search(&self, query: &[f32], top_k: usize, index: &IVFIndex) -> Vec<SearchResult> {
        // Find NPROBE nearest centroids
        let mut centroid_dists: Vec<(usize, f32)> = (0..NUM_CLUSTERS)
            .map(|c| {
                let centroid = &index.centroids[c * DIM..(c + 1) * DIM];
                (c, l2_distance_f32(query, centroid))
            })
            .collect();

        // Partial sort to find top NPROBE centroids
        centroid_dists.select_nth_unstable_by(NPROBE - 1, |a, b| a.1.partial_cmp(&b.1).unwrap());
        let probes = &mut centroid_dists[..NPROBE];

        // Use a simple sorted vec for top-k tracking (k=10 is small)
        let mut heap: Vec<(f32, u64)> = Vec::with_capacity(top_k + 1);
        let mut worst = f32::INFINITY;

        for &(cluster_id, _) in probes.iter() {
            let cluster_vecs = &index.cluster_data[cluster_id];
            let cluster_ids = &index.cluster_ids[cluster_id];
            let cluster_count = cluster_ids.len();

            if cluster_count == 0 { continue; }

            // Process vectors in this cluster
            for j in 0..cluster_count {
                let offset = j * DIM;
                let dist = l2_distance_f32(query, &cluster_vecs[offset..offset + DIM]);

                if heap.len() < top_k {
                    heap.push((dist, cluster_ids[j]));
                    if heap.len() == top_k {
                        worst = heap.iter().map(|x| x.0).fold(f32::NEG_INFINITY, f32::max);
                    }
                } else if dist < worst {
                    // Replace worst element
                    let worst_idx = heap.iter().enumerate()
                        .max_by(|a, b| a.1.0.partial_cmp(&b.1.0).unwrap())
                        .unwrap().0;
                    heap[worst_idx] = (dist, cluster_ids[j]);
                    worst = heap.iter().map(|x| x.0).fold(f32::NEG_INFINITY, f32::max);
                }
            }
        }

        // Sort by distance
        heap.sort_by(|a, b| a.0.partial_cmp(&b.0).unwrap());

        heap.iter().map(|&(dist, id)| SearchResult {
            id,
            distance: dist as f64,
        }).collect()
    }

    fn brute_force_search(&self, query: &[f32], top_k: usize) -> Vec<SearchResult> {
        let vecs = self.vectors.read();
        let ids_guard = self.ids.read();
        let n = ids_guard.len();

        if n == 0 {
            return Vec::new();
        }

        // Simple linear scan
        let mut heap: Vec<(f32, u64)> = Vec::with_capacity(top_k + 1);
        let mut worst = f32::INFINITY;

        for i in 0..n {
            let dist = l2_distance_f32(query, &vecs[i * DIM..(i + 1) * DIM]);
            if heap.len() < top_k {
                heap.push((dist, ids_guard[i]));
                if heap.len() == top_k {
                    worst = heap.iter().map(|x| x.0).fold(f32::NEG_INFINITY, f32::max);
                }
            } else if dist < worst {
                let worst_idx = heap.iter().enumerate()
                    .max_by(|a, b| a.1.0.partial_cmp(&b.1.0).unwrap())
                    .unwrap().0;
                heap[worst_idx] = (dist, ids_guard[i]);
                worst = heap.iter().map(|x| x.0).fold(f32::NEG_INFINITY, f32::max);
            }
        }

        heap.sort_by(|a, b| a.0.partial_cmp(&b.0).unwrap());

        heap.iter().map(|&(dist, id)| SearchResult {
            id,
            distance: dist as f64,
        }).collect()
    }
}

#[inline(always)]
fn find_nearest_centroid(vec: &[f32], centroids: &[f32], num_clusters: usize) -> usize {
    let mut best_idx = 0;
    let mut best_dist = f32::INFINITY;
    for c in 0..num_clusters {
        let centroid = &centroids[c * DIM..(c + 1) * DIM];
        let dist = l2_distance_f32(vec, centroid);
        if dist < best_dist {
            best_dist = dist;
            best_idx = c;
        }
    }
    best_idx
}
"}

{"path": "src/db.rs", "content": "use crate::api::*;
use crate::distance::l2_distance_f32;
use parking_lot::RwLock;
use rayon::prelude::*;
use std::sync::atomic::{AtomicBool, Ordering};

const DIM: usize = 128;
const NUM_CLUSTERS: usize = 1024;
const NPROBE: usize = 80;
const KMEANS_ITERS: usize = 12;
const KMEANS_SAMPLE_SIZE: usize = 80_000;

pub struct VectorDB {
    // Flat storage: all vectors stored contiguously
    vectors: RwLock<Vec<f32>>,  // DIM floats per vector
    ids: RwLock<Vec<u64>>,

    // IVF index
    index: RwLock<Option<IVFIndex>>,
    index_built: AtomicBool,
}

struct IVFIndex {
    centroids: Vec<f32>,     // NUM_CLUSTERS * DIM
    // For each cluster: vector IDs
    cluster_ids: Vec<Vec<u64>>,
    // For each cluster: contiguous vector data for cache-friendly access
    cluster_data: Vec<Vec<f32>>,
}

impl VectorDB {
    pub fn new() -> Self {
        // Initialize rayon with 4 threads to match pinned cores
        rayon::ThreadPoolBuilder::new()
            .num_threads(4)
            .build_global()
            .ok();

        VectorDB {
            vectors: RwLock::new(Vec::new()),
            ids: RwLock::new(Vec::new()),
            index: RwLock::new(None),
            index_built: AtomicBool::new(false),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        debug_assert_eq!(vector.len(), DIM);
        let mut vecs = self.vectors.write();
        let mut ids = self.ids.write();
        vecs.extend_from_slice(&vector);
        ids.push(id);
        // Invalidate index
        self.index_built.store(false, Ordering::Release);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let n = vectors.len();
        {
            let mut vecs = self.vectors.write();
            let mut ids = self.ids.write();
            vecs.reserve(n * DIM);
            ids.reserve(n);
            for (id, vector) in &vectors {
                debug_assert_eq!(vector.len(), DIM);
                vecs.extend_from_slice(vector);
                ids.push(*id);
            }
        }
        // Invalidate index
        self.index_built.store(false, Ordering::Release);
        n
    }

    fn ensure_index_built(&self) {
        if self.index_built.load(Ordering::Acquire) {
            return;
        }
        // Build index
        self.build_ivf_index();
    }

    fn build_ivf_index(&self) {
        let vecs = self.vectors.read();
        let ids_guard = self.ids.read();
        let n = ids_guard.len();

        if n < NUM_CLUSTERS * 2 {
            // Too few vectors for IVF, mark as built but use brute force
            self.index_built.store(true, Ordering::Release);
            return;
        }

        // Step 1: K-means clustering
        let centroids = kmeans_clustering(&vecs, n);

        // Step 2: Assign each vector to nearest centroid
        let assignments: Vec<usize> = (0..n).into_par_iter().map(|i| {
            let vec_data = &vecs[i * DIM..(i + 1) * DIM];
            find_nearest_centroid(vec_data, &centroids, NUM_CLUSTERS)
        }).collect();

        // Step 3: Build cluster data structures
        // First pass: count sizes
        let mut sizes = vec![0usize; NUM_CLUSTERS];
        for &a in &assignments {
            sizes[a] += 1;
        }

        let mut cluster_ids_vec: Vec<Vec<u64>> = sizes.iter().map(|&s| Vec::with_capacity(s)).collect();
        let mut cluster_data_vec: Vec<Vec<f32>> = sizes.iter().map(|&s| Vec::with_capacity(s * DIM)).collect();

        for (i, &cluster_id) in assignments.iter().enumerate() {
            cluster_ids_vec[cluster_id].push(ids_guard[i]);
            cluster_data_vec[cluster_id].extend_from_slice(&vecs[i * DIM..(i + 1) * DIM]);
        }

        let index = IVFIndex {
            centroids,
            cluster_ids: cluster_ids_vec,
            cluster_data: cluster_data_vec,
        };

        *self.index.write() = Some(index);
        self.index_built.store(true, Ordering::Release);
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let top_k = top_k as usize;

        // Ensure index is built (lazy building on first search)
        self.ensure_index_built();

        let index_guard = self.index.read();
        if let Some(ref index) = *index_guard {
            return self.ivf_search(vector, top_k, index);
        }

        // Fallback to brute-force for small datasets
        drop(index_guard);
        self.brute_force_search(vector, top_k)
    }

    fn ivf_search(&self, query: &[f32], top_k: usize, index: &IVFIndex) -> Vec<SearchResult> {
        // Find NPROBE nearest centroids
        let mut centroid_dists: Vec<(usize, f32)> = (0..NUM_CLUSTERS)
            .map(|c| {
                let centroid = &index.centroids[c * DIM..(c + 1) * DIM];
                (c, l2_distance_f32(query, centroid))
            })
            .collect();

        // Partial sort to find top NPROBE centroids
        centroid_dists.select_nth_unstable_by(NPROBE - 1, |a, b| a.1.partial_cmp(&b.1).unwrap());
        let probes = &centroid_dists[..NPROBE];

        // Use a simple array for top-k tracking (k=10 is small)
        let mut heap = TopK::new(top_k);

        for &(cluster_id, _) in probes.iter() {
            let cluster_vecs = &index.cluster_data[cluster_id];
            let cluster_ids = &index.cluster_ids[cluster_id];
            let cluster_count = cluster_ids.len();

            if cluster_count == 0 { continue; }

            // Process vectors in this cluster
            for j in 0..cluster_count {
                let offset = j * DIM;
                let dist = l2_distance_f32(query, &cluster_vecs[offset..offset + DIM]);
                heap.push(dist, cluster_ids[j]);
            }
        }

        heap.into_results()
    }

    fn brute_force_search(&self, query: &[f32], top_k: usize) -> Vec<SearchResult> {
        let vecs = self.vectors.read();
        let ids_guard = self.ids.read();
        let n = ids_guard.len();

        if n == 0 {
            return Vec::new();
        }

        let mut heap = TopK::new(top_k);

        for i in 0..n {
            let dist = l2_distance_f32(query, &vecs[i * DIM..(i + 1) * DIM]);
            heap.push(dist, ids_guard[i]);
        }

        heap.into_results()
    }
}

/// Simple top-k tracker using a small array (for k ~ 10)
struct TopK {
    items: Vec<(f32, u64)>,
    k: usize,
    worst: f32,
    worst_idx: usize,
}

impl TopK {
    fn new(k: usize) -> Self {
        TopK {
            items: Vec::with_capacity(k),
            k,
            worst: f32::INFINITY,
            worst_idx: 0,
        }
    }

    #[inline(always)]
    fn push(&mut self, dist: f32, id: u64) {
        if self.items.len() < self.k {
            self.items.push((dist, id));
            if self.items.len() == self.k {
                self.recompute_worst();
            }
        } else if dist < self.worst {
            self.items[self.worst_idx] = (dist, id);
            self.recompute_worst();
        }
    }

    #[inline(always)]
    fn recompute_worst(&mut self) {
        let mut widx = 0;
        let mut wdist = self.items[0].0;
        for i in 1..self.items.len() {
            if self.items[i].0 > wdist {
                wdist = self.items[i].0;
                widx = i;
            }
        }
        self.worst = wdist;
        self.worst_idx = widx;
    }

    fn into_results(mut self) -> Vec<SearchResult> {
        self.items.sort_by(|a, b| a.0.partial_cmp(&b.0).unwrap());
        self.items.iter().map(|&(dist, id)| SearchResult {
            id,
            distance: dist as f64,
        }).collect()
    }
}

#[inline(always)]
fn find_nearest_centroid(vec: &[f32], centroids: &[f32], num_clusters: usize) -> usize {
    let mut best_idx = 0;
    let mut best_dist = f32::INFINITY;
    for c in 0..num_clusters {
        let centroid = &centroids[c * DIM..(c + 1) * DIM];
        let dist = l2_distance_f32(vec, centroid);
        if dist < best_dist {
            best_dist = dist;
            best_idx = c;
        }
    }
    best_idx
}

fn kmeans_clustering(vecs: &[f32], n: usize) -> Vec<f32> {
    let sample_size = n.min(KMEANS_SAMPLE_SIZE);

    // Deterministic sampling: take evenly spaced vectors
    let step = if sample_size < n { n / sample_size } else { 1 };
    let sample_indices: Vec<usize> = (0..sample_size).map(|i| (i * step).min(n - 1)).collect();

    // Build contiguous sample data for faster access
    let mut sample_data = vec![0.0f32; sample_size * DIM];
    for (si, &idx) in sample_indices.iter().enumerate() {
        sample_data[si * DIM..(si + 1) * DIM].copy_from_slice(&vecs[idx * DIM..(idx + 1) * DIM]);
    }

    // Initialize centroids: pick evenly spaced from samples
    let mut centroids = vec![0.0f32; NUM_CLUSTERS * DIM];
    let centroid_step = sample_size / NUM_CLUSTERS;
    for c in 0..NUM_CLUSTERS {
        let src = c * centroid_step;
        centroids[c * DIM..(c + 1) * DIM].copy_from_slice(&sample_data[src * DIM..(src + 1) * DIM]);
    }

    // K-means iterations
    for _iter in 0..KMEANS_ITERS {
        // Assign samples to clusters (parallel)
        let assignments: Vec<usize> = (0..sample_size).into_par_iter().map(|si| {
            let vec_data = &sample_data[si * DIM..(si + 1) * DIM];
            find_nearest_centroid(vec_data, &centroids, NUM_CLUSTERS)
        }).collect();

        // Recompute centroids
        let mut new_centroids = vec![0.0f64; NUM_CLUSTERS * DIM];
        let mut counts = vec![0usize; NUM_CLUSTERS];

        for (si, &cluster_id) in assignments.iter().enumerate() {
            counts[cluster_id] += 1;
            let src_offset = si * DIM;
            for d in 0..DIM {
                new_centroids[cluster_id * DIM + d] += sample_data[src_offset + d] as f64;
            }
        }

        for c in 0..NUM_CLUSTERS {
            if counts[c] > 0 {
                let inv = 1.0 / counts[c] as f64;
                for d in 0..DIM {
                    centroids[c * DIM + d] = (new_centroids[c * DIM + d] * inv) as f32;
                }
            }
        }
    }

    centroids
}
