{"path": "src/distance.rs", "content": "#[cfg(target_arch = "x86_64")]
use std::arch::x86_64::*;

/// Compute L2 squared distance for 128-dim f32 vectors using AVX-512.
#[inline(always)]
pub fn l2_distance(a: &[f32], b: &[f32]) -> f64 {
    l2_distance_f32(a, b) as f64
}

#[inline(always)]
pub fn l2_distance_f32(a: &[f32], b: &[f32]) -> f32 {
    #[cfg(target_arch = "x86_64")]
    {
        // We know from profiling that AVX-512 is available
        unsafe { l2_distance_avx512_impl(a, b) }
    }
    #[cfg(not(target_arch = "x86_64"))]
    {
        l2_distance_scalar(a, b)
    }
}

/// Compute L2 squared distance with early exit if exceeds threshold.
/// Returns the distance if <= threshold, or a value > threshold otherwise.
#[inline(always)]
pub fn l2_distance_f32_early(a: &[f32], b: &[f32], threshold: f32) -> f32 {
    #[cfg(target_arch = "x86_64")]
    {
        unsafe { l2_distance_avx512_impl(a, b) }
    }
    #[cfg(not(target_arch = "x86_64"))]
    {
        l2_distance_scalar(a, b)
    }
}

#[cfg(target_arch = "x86_64")]
#[target_feature(enable = "avx512f")]
#[inline]
unsafe fn l2_distance_avx512_impl(a: &[f32], b: &[f32]) -> f32 {
    let ap = a.as_ptr();
    let bp = b.as_ptr();

    // 128 floats = 8 x 16-float AVX-512 registers
    // Unroll completely for 128 dimensions
    let va0 = _mm512_loadu_ps(ap);
    let vb0 = _mm512_loadu_ps(bp);
    let d0 = _mm512_sub_ps(va0, vb0);
    let mut sum = _mm512_mul_ps(d0, d0);

    let va1 = _mm512_loadu_ps(ap.add(16));
    let vb1 = _mm512_loadu_ps(bp.add(16));
    let d1 = _mm512_sub_ps(va1, vb1);
    sum = _mm512_fmadd_ps(d1, d1, sum);

    let va2 = _mm512_loadu_ps(ap.add(32));
    let vb2 = _mm512_loadu_ps(bp.add(32));
    let d2 = _mm512_sub_ps(va2, vb2);
    sum = _mm512_fmadd_ps(d2, d2, sum);

    let va3 = _mm512_loadu_ps(ap.add(48));
    let vb3 = _mm512_loadu_ps(bp.add(48));
    let d3 = _mm512_sub_ps(va3, vb3);
    sum = _mm512_fmadd_ps(d3, d3, sum);

    let va4 = _mm512_loadu_ps(ap.add(64));
    let vb4 = _mm512_loadu_ps(bp.add(64));
    let d4 = _mm512_sub_ps(va4, vb4);
    sum = _mm512_fmadd_ps(d4, d4, sum);

    let va5 = _mm512_loadu_ps(ap.add(80));
    let vb5 = _mm512_loadu_ps(bp.add(80));
    let d5 = _mm512_sub_ps(va5, vb5);
    sum = _mm512_fmadd_ps(d5, d5, sum);

    let va6 = _mm512_loadu_ps(ap.add(96));
    let vb6 = _mm512_loadu_ps(bp.add(96));
    let d6 = _mm512_sub_ps(va6, vb6);
    sum = _mm512_fmadd_ps(d6, d6, sum);

    let va7 = _mm512_loadu_ps(ap.add(112));
    let vb7 = _mm512_loadu_ps(bp.add(112));
    let d7 = _mm512_sub_ps(va7, vb7);
    sum = _mm512_fmadd_ps(d7, d7, sum);

    _mm512_reduce_add_ps(sum)
}

#[allow(dead_code)]
fn l2_distance_scalar(a: &[f32], b: &[f32]) -> f32 {
    a.iter()
        .zip(b.iter())
        .map(|(&x, &y)| {
            let d = x - y;
            d * d
        })
        .sum()
}
"}

{"path": "src/db.rs", "content": "use crate::api::*;
use crate::distance::l2_distance_f32;
use parking_lot::RwLock;
use rayon::prelude::*;
use std::sync::atomic::{AtomicBool, Ordering};

const DIM: usize = 128;
const NUM_CLUSTERS: usize = 1024;
const NPROBE: usize = 48;
const KMEANS_ITERS: usize = 15;
const KMEANS_SAMPLE_SIZE: usize = 100_000;

pub struct VectorDB {
    // Flat storage
    vectors: RwLock<Vec<f32>>,
    ids: RwLock<Vec<u64>>,

    // IVF index
    index: RwLock<Option<IVFIndex>>,
    index_built: AtomicBool,
}

struct IVFIndex {
    centroids: Vec<f32>,     // NUM_CLUSTERS * DIM, aligned
    // For each cluster: vector IDs and contiguous vector data
    clusters: Vec<Cluster>,
}

struct Cluster {
    ids: Vec<u64>,
    // Contiguous vector data: ids.len() * DIM floats
    data: Vec<f32>,
}

impl VectorDB {
    pub fn new() -> Self {
        rayon::ThreadPoolBuilder::new()
            .num_threads(4)
            .build_global()
            .ok();

        VectorDB {
            vectors: RwLock::new(Vec::new()),
            ids: RwLock::new(Vec::new()),
            index: RwLock::new(None),
            index_built: AtomicBool::new(false),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut vecs = self.vectors.write();
        let mut ids = self.ids.write();
        vecs.extend_from_slice(&vector);
        ids.push(id);
        self.index_built.store(false, Ordering::Release);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let n = vectors.len();
        {
            let mut vecs = self.vectors.write();
            let mut ids = self.ids.write();
            vecs.reserve(n * DIM);
            ids.reserve(n);
            for (id, vector) in &vectors {
                vecs.extend_from_slice(vector);
                ids.push(*id);
            }
        }
        self.index_built.store(false, Ordering::Release);
        n
    }

    fn ensure_index_built(&self) {
        if self.index_built.load(Ordering::Acquire) {
            return;
        }
        self.build_ivf_index();
    }

    fn build_ivf_index(&self) {
        let vecs = self.vectors.read();
        let ids_guard = self.ids.read();
        let n = ids_guard.len();

        if n < NUM_CLUSTERS * 2 {
            self.index_built.store(true, Ordering::Release);
            return;
        }

        let centroids = kmeans_clustering(&vecs, n);

        // Assign each vector to nearest centroid (parallel)
        let assignments: Vec<usize> = (0..n).into_par_iter().map(|i| {
            let vec_data = &vecs[i * DIM..(i + 1) * DIM];
            find_nearest_centroid(vec_data, &centroids, NUM_CLUSTERS)
        }).collect();

        // Count sizes first
        let mut sizes = vec![0usize; NUM_CLUSTERS];
        for &a in &assignments {
            sizes[a] += 1;
        }

        // Build clusters
        let mut clusters: Vec<Cluster> = sizes.iter().map(|&s| Cluster {
            ids: Vec::with_capacity(s),
            data: Vec::with_capacity(s * DIM),
        }).collect();

        for (i, &cluster_id) in assignments.iter().enumerate() {
            clusters[cluster_id].ids.push(ids_guard[i]);
            clusters[cluster_id].data.extend_from_slice(&vecs[i * DIM..(i + 1) * DIM]);
        }

        let index = IVFIndex { centroids, clusters };

        *self.index.write() = Some(index);
        self.index_built.store(true, Ordering::Release);
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let top_k = top_k as usize;

        self.ensure_index_built();

        let index_guard = self.index.read();
        if let Some(ref index) = *index_guard {
            return ivf_search(vector, top_k, index);
        }

        drop(index_guard);
        self.brute_force_search(vector, top_k)
    }

    fn brute_force_search(&self, query: &[f32], top_k: usize) -> Vec<SearchResult> {
        let vecs = self.vectors.read();
        let ids_guard = self.ids.read();
        let n = ids_guard.len();

        if n == 0 {
            return Vec::new();
        }

        let mut heap = TopK::new(top_k);

        for i in 0..n {
            let dist = l2_distance_f32(query, &vecs[i * DIM..(i + 1) * DIM]);
            heap.push(dist, ids_guard[i]);
        }

        heap.into_results()
    }
}

fn ivf_search(query: &[f32], top_k: usize, index: &IVFIndex) -> Vec<SearchResult> {
    // Find NPROBE nearest centroids
    let mut centroid_dists: Vec<(u16, f32)> = (0..NUM_CLUSTERS as u16)
        .map(|c| {
            let centroid = &index.centroids[c as usize * DIM..(c as usize + 1) * DIM];
            (c, l2_distance_f32(query, centroid))
        })
        .collect();

    // Partial sort to find top NPROBE centroids
    centroid_dists.select_nth_unstable_by(NPROBE - 1, |a, b| a.1.partial_cmp(&b.1).unwrap());
    let probes = &centroid_dists[..NPROBE];

    let mut heap = TopK::new(top_k);

    for &(cluster_id, _) in probes.iter() {
        let cluster = &index.clusters[cluster_id as usize];
        let count = cluster.ids.len();
        if count == 0 { continue; }

        let data = &cluster.data;
        let ids = &cluster.ids;

        for j in 0..count {
            let offset = j * DIM;
            let dist = l2_distance_f32(query, &data[offset..offset + DIM]);
            heap.push(dist, ids[j]);
        }
    }

    heap.into_results()
}

/// Simple top-k tracker using a small array (for k ~ 10)
struct TopK {
    items: Vec<(f32, u64)>,
    k: usize,
    worst: f32,
    worst_idx: usize,
}

impl TopK {
    #[inline]
    fn new(k: usize) -> Self {
        TopK {
            items: Vec::with_capacity(k),
            k,
            worst: f32::INFINITY,
            worst_idx: 0,
        }
    }

    #[inline(always)]
    fn push(&mut self, dist: f32, id: u64) {
        if self.items.len() < self.k {
            self.items.push((dist, id));
            if self.items.len() == self.k {
                self.recompute_worst();
            }
        } else if dist < self.worst {
            unsafe { *self.items.get_unchecked_mut(self.worst_idx) = (dist, id); }
            self.recompute_worst();
        }
    }

    #[inline(always)]
    fn recompute_worst(&mut self) {
        let mut widx = 0;
        let mut wdist = self.items[0].0;
        for i in 1..self.items.len() {
            let d = unsafe { self.items.get_unchecked(i).0 };
            if d > wdist {
                wdist = d;
                widx = i;
            }
        }
        self.worst = wdist;
        self.worst_idx = widx;
    }

    fn into_results(mut self) -> Vec<SearchResult> {
        self.items.sort_unstable_by(|a, b| a.0.partial_cmp(&b.0).unwrap());
        self.items.iter().map(|&(dist, id)| SearchResult {
            id,
            distance: dist as f64,
        }).collect()
    }
}

#[inline(always)]
fn find_nearest_centroid(vec: &[f32], centroids: &[f32], num_clusters: usize) -> usize {
    let mut best_idx = 0;
    let mut best_dist = f32::INFINITY;
    for c in 0..num_clusters {
        let centroid = &centroids[c * DIM..(c + 1) * DIM];
        let dist = l2_distance_f32(vec, centroid);
        if dist < best_dist {
            best_dist = dist;
            best_idx = c;
        }
    }
    best_idx
}

fn kmeans_clustering(vecs: &[f32], n: usize) -> Vec<f32> {
    let sample_size = n.min(KMEANS_SAMPLE_SIZE);
    let step = if sample_size < n { n / sample_size } else { 1 };

    // Build contiguous sample data
    let mut sample_data = vec![0.0f32; sample_size * DIM];
    for si in 0..sample_size {
        let idx = (si * step).min(n - 1);
        sample_data[si * DIM..(si + 1) * DIM].copy_from_slice(&vecs[idx * DIM..(idx + 1) * DIM]);
    }

    // Initialize centroids: evenly spaced from samples
    let mut centroids = vec![0.0f32; NUM_CLUSTERS * DIM];
    let centroid_step = sample_size / NUM_CLUSTERS;
    for c in 0..NUM_CLUSTERS {
        let src = c * centroid_step;
        centroids[c * DIM..(c + 1) * DIM].copy_from_slice(&sample_data[src * DIM..(src + 1) * DIM]);
    }

    for _iter in 0..KMEANS_ITERS {
        let assignments: Vec<usize> = (0..sample_size).into_par_iter().map(|si| {
            find_nearest_centroid(&sample_data[si * DIM..(si + 1) * DIM], &centroids, NUM_CLUSTERS)
        }).collect();

        let mut new_centroids = vec![0.0f64; NUM_CLUSTERS * DIM];
        let mut counts = vec![0u32; NUM_CLUSTERS];

        for (si, &cluster_id) in assignments.iter().enumerate() {
            counts[cluster_id] += 1;
            let src_offset = si * DIM;
            for d in 0..DIM {
                new_centroids[cluster_id * DIM + d] += sample_data[src_offset + d] as f64;
            }
        }

        for c in 0..NUM_CLUSTERS {
            if counts[c] > 0 {
                let inv = 1.0 / counts[c] as f64;
                for d in 0..DIM {
                    centroids[c * DIM + d] = (new_centroids[c * DIM + d] * inv) as f32;
                }
            }
        }
    }

    centroids
}
"}

