#[inline(never)]
fn ivf_search(query: &[f32], top_k: usize, index: &IVFIndex) -> Vec<SearchResult> {
    // Find NPROBE nearest centroids
    let mut centroid_dists = Vec::with_capacity(NUM_CLUSTERS);
    for c in 0..NUM_CLUSTERS {
        let centroid = &index.centroids[c * DIM..(c + 1) * DIM];
        centroid_dists.push((c as u16, l2_distance_f32(query, centroid)));
    }

    centroid_dists.select_nth_unstable_by(NPROBE - 1, |a, b| a.1.partial_cmp(&b.1).unwrap());

    let mut heap = TopK::new(top_k);

    for i in 0..NPROBE {
        let cluster_id = centroid_dists[i].0 as usize;
        let cluster = &index.clusters[cluster_id];
        let count = cluster.ids.len();
        if count == 0 { continue; }

        let data = cluster.data.as_ptr();
        let ids = &cluster.ids;
        let worst = heap.worst;

        for j in 0..count {
            let dist = l2_distance_f32(query, unsafe { 
                std::slice::from_raw_parts(data.add(j * DIM), DIM) 
            });
            if dist < worst || heap.items.len() < heap.k {
                heap.push(dist, ids[j]);
            }
        }
    }

    heap.into_results()
}

