{"path": "src/db.rs", "content": "use crate::api::*;
use crate::distance::l2_distance_f32;
use parking_lot::RwLock;
use rayon::prelude::*;
use std::sync::atomic::{AtomicBool, Ordering};

const DIM: usize = 128;

// Two-level IVF: coarse level with few clusters for fast centroid search
// Fine level subdivides each coarse cluster
const COARSE_CLUSTERS: usize = 128;
const FINE_CLUSTERS_PER_COARSE: usize = 16;
const TOTAL_FINE: usize = COARSE_CLUSTERS * FINE_CLUSTERS_PER_COARSE; // 2048
const COARSE_NPROBE: usize = 16; // Search top-16 coarse clusters 
const FINE_NPROBE_PER_COARSE: usize = 5; // Search top-5 fine clusters within each coarse

const KMEANS_ITERS: usize = 12;
const KMEANS_SAMPLE_SIZE: usize = 120_000;

pub struct VectorDB {
    vectors: RwLock<Vec<f32>>,
    ids: RwLock<Vec<u64>>,
    index: RwLock<Option<Box<IVFIndex>>>,
    index_built: AtomicBool,
}

struct IVFIndex {
    // Coarse centroids: COARSE_CLUSTERS * DIM
    coarse_centroids: Vec<f32>,
    // For each coarse cluster: fine centroids (FINE_CLUSTERS_PER_COARSE * DIM) 
    fine_centroids: Vec<Vec<f32>>,
    // For each coarse cluster, for each fine cluster: vectors
    clusters: Vec<Vec<Cluster>>, // [coarse][fine]
}

struct Cluster {
    ids: Vec<u64>,
    data: Vec<f32>,
}

unsafe impl Send for IVFIndex {}
unsafe impl Sync for IVFIndex {}

impl VectorDB {
    pub fn new() -> Self {
        rayon::ThreadPoolBuilder::new()
            .num_threads(4)
            .build_global()
            .ok();

        VectorDB {
            vectors: RwLock::new(Vec::new()),
            ids: RwLock::new(Vec::new()),
            index: RwLock::new(None),
            index_built: AtomicBool::new(false),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut vecs = self.vectors.write();
        let mut ids = self.ids.write();
        vecs.extend_from_slice(&vector);
        ids.push(id);
        self.index_built.store(false, Ordering::Release);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let n = vectors.len();
        {
            let mut vecs = self.vectors.write();
            let mut ids = self.ids.write();
            vecs.reserve(n * DIM);
            ids.reserve(n);
            for (id, vector) in &vectors {
                vecs.extend_from_slice(vector);
                ids.push(*id);
            }
        }
        self.index_built.store(false, Ordering::Release);
        n
    }

    fn ensure_index_built(&self) {
        if self.index_built.load(Ordering::Acquire) {
            return;
        }
        self.build_index();
    }

    fn build_index(&self) {
        let vecs = self.vectors.read();
        let ids_guard = self.ids.read();
        let n = ids_guard.len();

        if n < TOTAL_FINE * 2 {
            self.index_built.store(true, Ordering::Release);
            return;
        }

        // Step 1: Coarse clustering
        let coarse_centroids = kmeans_clustering(&vecs, n, COARSE_CLUSTERS);

        // Step 2: Assign to coarse clusters
        let coarse_assignments: Vec<u8> = (0..n).into_par_iter().map(|i| {
            find_nearest_centroid(&vecs[i * DIM..(i + 1) * DIM], &coarse_centroids, COARSE_CLUSTERS) as u8
        }).collect();

        // Step 3: For each coarse cluster, do fine clustering
        // First collect vectors per coarse cluster
        let mut coarse_sizes = vec![0usize; COARSE_CLUSTERS];
        for &a in &coarse_assignments {
            coarse_sizes[a as usize] += 1;
        }

        let mut coarse_vecs: Vec<Vec<usize>> = coarse_sizes.iter().map(|&s| Vec::with_capacity(s)).collect();
        for (i, &c) in coarse_assignments.iter().enumerate() {
            coarse_vecs[c as usize].push(i);
        }

        // Fine clustering per coarse cluster (parallel)
        let fine_results: Vec<(Vec<f32>, Vec<Vec<Cluster>>)> = (0..COARSE_CLUSTERS).into_par_iter().map(|cc| {
            let indices = &coarse_vecs[cc];
            let count = indices.len();

            if count < FINE_CLUSTERS_PER_COARSE * 2 {
                // Too few vectors, put all in one cluster
                let mut fine_centroids = vec![0.0f32; FINE_CLUSTERS_PER_COARSE * DIM];
                let mut single_cluster = Cluster {
                    ids: Vec::with_capacity(count),
                    data: Vec::with_capacity(count * DIM),
                };
                // Compute mean as centroid
                if count > 0 {
                    let mut mean = vec![0.0f64; DIM];
                    for &idx in indices {
                        single_cluster.ids.push(ids_guard[idx]);
                        single_cluster.data.extend_from_slice(&vecs[idx * DIM..(idx + 1) * DIM]);
                        for d in 0..DIM {
                            mean[d] += vecs[idx * DIM + d] as f64;
                        }
                    }
                    let inv = 1.0 / count as f64;
                    for d in 0..DIM {
                        fine_centroids[d] = (mean[d] * inv) as f32;
                    }
                }
                let mut fine_clusters = vec![Cluster { ids: Vec::new(), data: Vec::new() }; FINE_CLUSTERS_PER_COARSE];
                fine_clusters[0] = single_cluster;
                return (fine_centroids, vec![fine_clusters]);
            }

            // Build local data
            let mut local_data = vec![0.0f32; count * DIM];
            for (li, &idx) in indices.iter().enumerate() {
                local_data[li * DIM..(li + 1) * DIM].copy_from_slice(&vecs[idx * DIM..(idx + 1) * DIM]);
            }

            let fine_centroids = kmeans_local(&local_data, count, FINE_CLUSTERS_PER_COARSE, 8);

            // Assign to fine clusters
            let mut fine_sizes = vec![0usize; FINE_CLUSTERS_PER_COARSE];
            let fine_assignments: Vec<usize> = (0..count).map(|li| {
                let a = find_nearest_centroid(&local_data[li * DIM..(li + 1) * DIM], &fine_centroids, FINE_CLUSTERS_PER_COARSE);
                fine_sizes[a] += 1;
                a
            }).collect();

            let mut fine_clusters: Vec<Cluster> = fine_sizes.iter().map(|&s| Cluster {
                ids: Vec::with_capacity(s),
                data: Vec::with_capacity(s * DIM),
            }).collect();

            for (li, &fc) in fine_assignments.iter().enumerate() {
                let orig_idx = indices[li];
                fine_clusters[fc].ids.push(ids_guard[orig_idx]);
                fine_clusters[fc].data.extend_from_slice(&local_data[li * DIM..(li + 1) * DIM]);
            }

            (fine_centroids, vec![fine_clusters])
        }).collect();

        let mut fine_centroids_all = Vec::with_capacity(COARSE_CLUSTERS);
        let mut clusters_all = Vec::with_capacity(COARSE_CLUSTERS);

        for (fc, mut cl) in fine_results {
            fine_centroids_all.push(fc);
            clusters_all.push(cl.pop().unwrap());
        }

        *self.index.write() = Some(Box::new(IVFIndex {
            coarse_centroids,
            fine_centroids: fine_centroids_all,
            clusters: clusters_all,
        }));
        self.index_built.store(true, Ordering::Release);
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let top_k = top_k as usize;
        self.ensure_index_built();

        let index_guard = self.index.read();
        if let Some(ref index) = *index_guard {
            return ivf_search(vector, top_k, index);
        }

        drop(index_guard);
        self.brute_force_search(vector, top_k)
    }

    fn brute_force_search(&self, query: &[f32], top_k: usize) -> Vec<SearchResult> {
        let vecs = self.vectors.read();
        let ids_guard = self.ids.read();
        let n = ids_guard.len();
        if n == 0 { return Vec::new(); }

        let mut heap = TopK::new(top_k);
        for i in 0..n {
            let dist = l2_distance_f32(query, &vecs[i * DIM..(i + 1) * DIM]);
            heap.push(dist, ids_guard[i]);
        }
        heap.into_results()
    }
}

#[inline(never)]
fn ivf_search(query: &[f32], top_k: usize, index: &IVFIndex) -> Vec<SearchResult> {
    // Step 1: Find nearest coarse clusters (128 centroids - fast)
    let mut coarse_dists: Vec<(u8, f32)> = Vec::with_capacity(COARSE_CLUSTERS);
    for c in 0..COARSE_CLUSTERS {
        let dist = l2_distance_f32(query, &index.coarse_centroids[c * DIM..(c + 1) * DIM]);
        coarse_dists.push((c as u8, dist));
    }

    coarse_dists.select_nth_unstable_by(COARSE_NPROBE - 1, |a, b| a.1.partial_cmp(&b.1).unwrap());

    let mut heap = TopK::new(top_k);

    // Step 2: For each selected coarse cluster, find nearest fine clusters
    for ci in 0..COARSE_NPROBE {
        let coarse_id = coarse_dists[ci].0 as usize;
        let fine_centroids = &index.fine_centroids[coarse_id];
        let fine_clusters = &index.clusters[coarse_id];

        // Find nearest fine clusters (16 centroids - very fast)
        let mut fine_dists: Vec<(u8, f32)> = Vec::with_capacity(FINE_CLUSTERS_PER_COARSE);
        for f in 0..FINE_CLUSTERS_PER_COARSE {
            let dist = l2_distance_f32(query, &fine_centroids[f * DIM..(f + 1) * DIM]);
            fine_dists.push((f as u8, dist));
        }

        let nprobe_fine = FINE_NPROBE_PER_COARSE.min(FINE_CLUSTERS_PER_COARSE);
        fine_dists.select_nth_unstable_by(nprobe_fine - 1, |a, b| a.1.partial_cmp(&b.1).unwrap());

        for fi in 0..nprobe_fine {
            let fine_id = fine_dists[fi].0 as usize;
            let cluster = &fine_clusters[fine_id];
            let count = cluster.ids.len();
            if count == 0 { continue; }

            let data_ptr = cluster.data.as_ptr();
            let ids = &cluster.ids;

            for j in 0..count {
                let dist = l2_distance_f32(query, unsafe {
                    std::slice::from_raw_parts(data_ptr.add(j * DIM), DIM)
                });
                if dist < heap.worst || heap.items.len() < heap.k {
                    heap.push_unchecked(dist, ids[j]);
                }
            }
        }
    }

    heap.into_results()
}

struct TopK {
    items: Vec<(f32, u64)>,
    k: usize,
    worst: f32,
    worst_idx: usize,
}

impl TopK {
    #[inline]
    fn new(k: usize) -> Self {
        TopK {
            items: Vec::with_capacity(k),
            k,
            worst: f32::INFINITY,
            worst_idx: 0,
        }
    }

    #[inline(always)]
    fn push(&mut self, dist: f32, id: u64) {
        if self.items.len() < self.k {
            self.items.push((dist, id));
            if self.items.len() == self.k {
                self.recompute_worst();
            }
        } else if dist < self.worst {
            unsafe { *self.items.get_unchecked_mut(self.worst_idx) = (dist, id); }
            self.recompute_worst();
        }
    }

    #[inline(always)]
    fn push_unchecked(&mut self, dist: f32, id: u64) {
        if self.items.len() < self.k {
            self.items.push((dist, id));
            if self.items.len() == self.k {
                self.recompute_worst();
            }
        } else {
            unsafe { *self.items.get_unchecked_mut(self.worst_idx) = (dist, id); }
            self.recompute_worst();
        }
    }

    #[inline(always)]
    fn recompute_worst(&mut self) {
        let mut widx = 0;
        let mut wdist = unsafe { self.items.get_unchecked(0).0 };
        for i in 1..self.items.len() {
            let d = unsafe { self.items.get_unchecked(i).0 };
            if d > wdist {
                wdist = d;
                widx = i;
            }
        }
        self.worst = wdist;
        self.worst_idx = widx;
    }

    fn into_results(mut self) -> Vec<SearchResult> {
        self.items.sort_unstable_by(|a, b| a.0.partial_cmp(&b.0).unwrap());
        self.items.iter().map(|&(dist, id)| SearchResult {
            id,
            distance: dist as f64,
        }).collect()
    }
}

#[inline(always)]
fn find_nearest_centroid(vec: &[f32], centroids: &[f32], num_clusters: usize) -> usize {
    let mut best_idx = 0;
    let mut best_dist = f32::INFINITY;
    for c in 0..num_clusters {
        let dist = l2_distance_f32(vec, &centroids[c * DIM..(c + 1) * DIM]);
        if dist < best_dist {
            best_dist = dist;
            best_idx = c;
        }
    }
    best_idx
}

fn kmeans_clustering(vecs: &[f32], n: usize, num_clusters: usize) -> Vec<f32> {
    let sample_size = n.min(KMEANS_SAMPLE_SIZE);
    let step = if sample_size < n { n / sample_size } else { 1 };

    let mut sample_data = vec![0.0f32; sample_size * DIM];
    for si in 0..sample_size {
        let idx = (si * step).min(n - 1);
        sample_data[si * DIM..(si + 1) * DIM].copy_from_slice(&vecs[idx * DIM..(idx + 1) * DIM]);
    }

    kmeans_local(&sample_data, sample_size, num_clusters, KMEANS_ITERS)
}

fn kmeans_local(data: &[f32], n: usize, num_clusters: usize, iters: usize) -> Vec<f32> {
    let actual_clusters = num_clusters.min(n);
    let mut centroids = vec![0.0f32; num_clusters * DIM];
    let centroid_step = (n / actual_clusters).max(1);
    for c in 0..actual_clusters {
        let src = (c * centroid_step).min(n - 1);
        centroids[c * DIM..(c + 1) * DIM].copy_from_slice(&data[src * DIM..(src + 1) * DIM]);
    }

    for _iter in 0..iters {
        let mut new_centroids = vec![0.0f64; num_clusters * DIM];
        let mut counts = vec![0u32; num_clusters];

        for si in 0..n {
            let cluster_id = find_nearest_centroid(&data[si * DIM..(si + 1) * DIM], &centroids, num_clusters);
            counts[cluster_id] += 1;
            let src_offset = si * DIM;
            for d in 0..DIM {
                new_centroids[cluster_id * DIM + d] += data[src_offset + d] as f64;
            }
        }

        for c in 0..num_clusters {
            if counts[c] > 0 {
                let inv = 1.0 / counts[c] as f64;
                for d in 0..DIM {
                    centroids[c * DIM + d] = (new_centroids[c * DIM + d] * inv) as f32;
                }
            }
        }
    }

    centroids
}
"}

