use std::arch::x86_64::*;

/// Compute L2 squared distance for 128-dim f32 vectors.
#[inline(always)]
pub fn l2_distance(a: &[f32], b: &[f32]) -> f64 {
    l2_distance_f32(a, b) as f64
}

#[inline(always)]
pub fn l2_distance_f32(a: &[f32], b: &[f32]) -> f32 {
    unsafe { l2_distance_avx512_impl(a, b) }
}

/// Compute dot product for 128-dim f32 vectors using AVX-512.
#[inline(always)]
pub fn dot_product_f32(a: &[f32], b: &[f32]) -> f32 {
    unsafe { dot_product_avx512_impl(a, b) }
}

/// Compute squared norm of a 128-dim f32 vector.
#[inline(always)]
pub fn squared_norm_f32(a: &[f32]) -> f32 {
    unsafe { dot_product_avx512_impl(a, a) }
}

#[cfg(target_arch = "x86_64")]
#[target_feature(enable = "avx512f")]
#[inline]
unsafe fn l2_distance_avx512_impl(a: &[f32], b: &[f32]) -> f32 {
    let ap = a.as_ptr();
    let bp = b.as_ptr();

    let d0 = _mm512_sub_ps(_mm512_loadu_ps(ap), _mm512_loadu_ps(bp));
    let mut sum = _mm512_mul_ps(d0, d0);

    let d1 = _mm512_sub_ps(_mm512_loadu_ps(ap.add(16)), _mm512_loadu_ps(bp.add(16)));
    sum = _mm512_fmadd_ps(d1, d1, sum);

    let d2 = _mm512_sub_ps(_mm512_loadu_ps(ap.add(32)), _mm512_loadu_ps(bp.add(32)));
    sum = _mm512_fmadd_ps(d2, d2, sum);

    let d3 = _mm512_sub_ps(_mm512_loadu_ps(ap.add(48)), _mm512_loadu_ps(bp.add(48)));
    sum = _mm512_fmadd_ps(d3, d3, sum);

    let d4 = _mm512_sub_ps(_mm512_loadu_ps(ap.add(64)), _mm512_loadu_ps(bp.add(64)));
    sum = _mm512_fmadd_ps(d4, d4, sum);

    let d5 = _mm512_sub_ps(_mm512_loadu_ps(ap.add(80)), _mm512_loadu_ps(bp.add(80)));
    sum = _mm512_fmadd_ps(d5, d5, sum);

    let d6 = _mm512_sub_ps(_mm512_loadu_ps(ap.add(96)), _mm512_loadu_ps(bp.add(96)));
    sum = _mm512_fmadd_ps(d6, d6, sum);

    let d7 = _mm512_sub_ps(_mm512_loadu_ps(ap.add(112)), _mm512_loadu_ps(bp.add(112)));
    sum = _mm512_fmadd_ps(d7, d7, sum);

    _mm512_reduce_add_ps(sum)
}

#[cfg(target_arch = "x86_64")]
#[target_feature(enable = "avx512f")]
#[inline]
unsafe fn dot_product_avx512_impl(a: &[f32], b: &[f32]) -> f32 {
    let ap = a.as_ptr();
    let bp = b.as_ptr();

    let mut sum = _mm512_mul_ps(_mm512_loadu_ps(ap), _mm512_loadu_ps(bp));
    sum = _mm512_fmadd_ps(_mm512_loadu_ps(ap.add(16)), _mm512_loadu_ps(bp.add(16)), sum);
    sum = _mm512_fmadd_ps(_mm512_loadu_ps(ap.add(32)), _mm512_loadu_ps(bp.add(32)), sum);
    sum = _mm512_fmadd_ps(_mm512_loadu_ps(ap.add(48)), _mm512_loadu_ps(bp.add(48)), sum);
    sum = _mm512_fmadd_ps(_mm512_loadu_ps(ap.add(64)), _mm512_loadu_ps(bp.add(64)), sum);
    sum = _mm512_fmadd_ps(_mm512_loadu_ps(ap.add(80)), _mm512_loadu_ps(bp.add(80)), sum);
    sum = _mm512_fmadd_ps(_mm512_loadu_ps(ap.add(96)), _mm512_loadu_ps(bp.add(96)), sum);
    sum = _mm512_fmadd_ps(_mm512_loadu_ps(ap.add(112)), _mm512_loadu_ps(bp.add(112)), sum);

    _mm512_reduce_add_ps(sum)
}
"}

{"path": "src/db.rs", "content": "use crate::api::*;
use crate::distance::{l2_distance_f32, squared_norm_f32, dot_product_f32};
use parking_lot::RwLock;
use rayon::prelude::*;
use std::sync::atomic::{AtomicBool, Ordering};

const DIM: usize = 128;
const NUM_CLUSTERS: usize = 4096;
const NPROBE: usize = 52;
const KMEANS_ITERS: usize = 14;
const KMEANS_SAMPLE_SIZE: usize = 150_000;

pub struct VectorDB {
    vectors: RwLock<Vec<f32>>,
    ids: RwLock<Vec<u64>>,
    index: RwLock<Option<Box<IVFIndex>>>,
    index_built: AtomicBool,
}

struct IVFIndex {
    centroids: Vec<f32>,       // NUM_CLUSTERS * DIM
    centroid_norms: Vec<f32>,  // NUM_CLUSTERS - precomputed ||c||^2
    clusters: Vec<Cluster>,
}

struct Cluster {
    ids: Vec<u64>,
    data: Vec<f32>,
    norms: Vec<f32>,  // precomputed ||v||^2 for each vector
}

unsafe impl Send for IVFIndex {}
unsafe impl Sync for IVFIndex {}

impl VectorDB {
    pub fn new() -> Self {
        rayon::ThreadPoolBuilder::new()
            .num_threads(4)
            .build_global()
            .ok();

        VectorDB {
            vectors: RwLock::new(Vec::new()),
            ids: RwLock::new(Vec::new()),
            index: RwLock::new(None),
            index_built: AtomicBool::new(false),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut vecs = self.vectors.write();
        let mut ids = self.ids.write();
        vecs.extend_from_slice(&vector);
        ids.push(id);
        self.index_built.store(false, Ordering::Release);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let n = vectors.len();
        {
            let mut vecs = self.vectors.write();
            let mut ids = self.ids.write();
            vecs.reserve(n * DIM);
            ids.reserve(n);
            for (id, vector) in &vectors {
                vecs.extend_from_slice(vector);
                ids.push(*id);
            }
        }
        self.index_built.store(false, Ordering::Release);
        n
    }

    fn ensure_index_built(&self) {
        if self.index_built.load(Ordering::Acquire) {
            return;
        }
        self.build_ivf_index();
    }

    fn build_ivf_index(&self) {
        let vecs = self.vectors.read();
        let ids_guard = self.ids.read();
        let n = ids_guard.len();

        if n < NUM_CLUSTERS * 2 {
            self.index_built.store(true, Ordering::Release);
            return;
        }

        let centroids = kmeans_clustering(&vecs, n);

        // Precompute centroid norms
        let centroid_norms: Vec<f32> = (0..NUM_CLUSTERS).map(|c| {
            squared_norm_f32(&centroids[c * DIM..(c + 1) * DIM])
        }).collect();

        let assignments: Vec<u16> = (0..n).into_par_iter().map(|i| {
            find_nearest_centroid(&vecs[i * DIM..(i + 1) * DIM], &centroids, NUM_CLUSTERS) as u16
        }).collect();

        let mut sizes = vec![0usize; NUM_CLUSTERS];
        for &a in &assignments {
            sizes[a as usize] += 1;
        }

        let mut clusters: Vec<Cluster> = sizes.iter().map(|&s| Cluster {
            ids: Vec::with_capacity(s),
            data: Vec::with_capacity(s * DIM),
            norms: Vec::with_capacity(s),
        }).collect();

        for (i, &cluster_id) in assignments.iter().enumerate() {
            let c = cluster_id as usize;
            clusters[c].ids.push(ids_guard[i]);
            let vec_slice = &vecs[i * DIM..(i + 1) * DIM];
            clusters[c].data.extend_from_slice(vec_slice);
            clusters[c].norms.push(squared_norm_f32(vec_slice));
        }

        *self.index.write() = Some(Box::new(IVFIndex { centroids, centroid_norms, clusters }));
        self.index_built.store(true, Ordering::Release);
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let top_k = top_k as usize;
        self.ensure_index_built();

        let index_guard = self.index.read();
        if let Some(ref index) = *index_guard {
            return ivf_search(vector, top_k, index);
        }

        drop(index_guard);
        self.brute_force_search(vector, top_k)
    }

    fn brute_force_search(&self, query: &[f32], top_k: usize) -> Vec<SearchResult> {
        let vecs = self.vectors.read();
        let ids_guard = self.ids.read();
        let n = ids_guard.len();
        if n == 0 { return Vec::new(); }

        let mut heap = TopK::new(top_k);
        for i in 0..n {
            let dist = l2_distance_f32(query, &vecs[i * DIM..(i + 1) * DIM]);
            heap.push(dist, ids_guard[i]);
        }
        heap.into_results()
    }
}

#[inline(never)]
fn ivf_search(query: &[f32], top_k: usize, index: &IVFIndex) -> Vec<SearchResult> {
    let query_norm = squared_norm_f32(query);

    // Compute distances to all centroids using: ||q-c||^2 = ||q||^2 + ||c||^2 - 2*q·c
    let mut centroid_dists: Vec<(u16, f32)> = Vec::with_capacity(NUM_CLUSTERS);
    for c in 0..NUM_CLUSTERS {
        let dot = dot_product_f32(query, &index.centroids[c * DIM..(c + 1) * DIM]);
        let dist = query_norm + index.centroid_norms[c] - 2.0 * dot;
        centroid_dists.push((c as u16, dist));
    }

    // Select top NPROBE
    centroid_dists.select_nth_unstable_by(NPROBE - 1, |a, b| a.1.partial_cmp(&b.1).unwrap());

    let mut heap = TopK::new(top_k);

    for i in 0..NPROBE {
        let cluster_id = centroid_dists[i].0 as usize;
        let cluster = &index.clusters[cluster_id];
        let count = cluster.ids.len();
        if count == 0 { continue; }

        let data = &cluster.data;
        let ids = &cluster.ids;
        let norms = &cluster.norms;

        for j in 0..count {
            // Use norm-based distance: ||q-v||^2 = ||q||^2 + ||v||^2 - 2*q·v
            let dot = dot_product_f32(query, unsafe {
                data.get_unchecked(j * DIM..(j + 1) * DIM)
            });
            let dist = query_norm + unsafe { *norms.get_unchecked(j) } - 2.0 * dot;
            if dist < heap.worst || heap.items.len() < heap.k {
                heap.push_unchecked(dist, unsafe { *ids.get_unchecked(j) });
            }
        }
    }

    heap.into_results()
}

struct TopK {
    items: Vec<(f32, u64)>,
    k: usize,
    worst: f32,
    worst_idx: usize,
}

impl TopK {
    #[inline]
