const NUM_SUPER_CLUSTERS: usize = 64;  // 64 super-clusters of 64 centroids each
const SUPER_NPROBE: usize = 12;        // Check top-12 super-clusters
// This reduces centroid search from 4096 to 64 + 12*64 = 832 distance computations

pub struct VectorDB {
    vectors: RwLock<Vec<f32>>,
    ids: RwLock<Vec<u64>>,
    index: RwLock<Option<Box<IVFIndex>>>,
    index_built: AtomicBool,
}

struct IVFIndex {
    centroids: Vec<f32>,       // NUM_CLUSTERS * DIM
    clusters: Vec<Cluster>,
    // Hierarchical: super-cluster centroids and membership
    super_centroids: Vec<f32>,      // NUM_SUPER_CLUSTERS * DIM
    super_members: Vec<Vec<u16>>,   // For each super-cluster, which centroids belong to it
}

struct Cluster {
    ids: Vec<u64>,
    data: Vec<f32>,
}

unsafe impl Send for IVFIndex {}
unsafe impl Sync for IVFIndex {}

impl VectorDB {
    pub fn new() -> Self {
        rayon::ThreadPoolBuilder::new()
            .num_threads(4)
            .build_global()
            .ok();

        VectorDB {
            vectors: RwLock::new(Vec::new()),
            ids: RwLock::new(Vec::new()),
            index: RwLock::new(None),
            index_built: AtomicBool::new(false),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut vecs = self.vectors.write();
        let mut ids = self.ids.write();
        vecs.extend_from_slice(&vector);
        ids.push(id);
        self.index_built.store(false, Ordering::Release);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let n = vectors.len();
        {
            let mut vecs = self.vectors.write();
            let mut ids = self.ids.write();
            vecs.reserve(n * DIM);
            ids.reserve(n);
            for (id, vector) in &vectors {
                vecs.extend_from_slice(vector);
                ids.push(*id);
            }
        }
        self.index_built.store(false, Ordering::Release);
        n
    }

    fn ensure_index_built(&self) {
        if self.index_built.load(Ordering::Acquire) {
            return;
        }
        self.build_ivf_index();
    }

    fn build_ivf_index(&self) {
        let vecs = self.vectors.read();
        let ids_guard = self.ids.read();
        let n = ids_guard.len();

        if n < NUM_CLUSTERS * 2 {
            self.index_built.store(true, Ordering::Release);
            return;
        }

        let centroids = kmeans_clustering(&vecs, n);

        // Build super-clusters from centroids
        let super_centroids = kmeans_local(&centroids, NUM_CLUSTERS, NUM_SUPER_CLUSTERS, 10);

        // Assign each centroid to nearest super-cluster
        let mut super_members: Vec<Vec<u16>> = vec![Vec::new(); NUM_SUPER_CLUSTERS];
        for c in 0..NUM_CLUSTERS {
            let sc = find_nearest_centroid(&centroids[c * DIM..(c + 1) * DIM], &super_centroids, NUM_SUPER_CLUSTERS);
            super_members[sc].push(c as u16);
        }

        // Assign vectors to clusters
        let assignments: Vec<u16> = (0..n).into_par_iter().map(|i| {
            find_nearest_centroid(&vecs[i * DIM..(i + 1) * DIM], &centroids, NUM_CLUSTERS) as u16
        }).collect();

        let mut sizes = vec![0usize; NUM_CLUSTERS];
        for &a in &assignments {
            sizes[a as usize] += 1;
        }

        let mut clusters: Vec<Cluster> = sizes.iter().map(|&s| Cluster {
            ids: Vec::with_capacity(s),
            data: Vec::with_capacity(s * DIM),
        }).collect();

        for (i, &cluster_id) in assignments.iter().enumerate() {
            let c = cluster_id as usize;
            clusters[c].ids.push(ids_guard[i]);
            clusters[c].data.extend_from_slice(&vecs[i * DIM..(i + 1) * DIM]);
        }

        *self.index.write() = Some(Box::new(IVFIndex { 
            centroids, clusters, super_centroids, super_members 
        }));
        self.index_built.store(true, Ordering::Release);
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let top_k = top_k as usize;
        self.ensure_index_built();

        let index_guard = self.index.read();
        if let Some(ref index) = *index_guard {
            return ivf_search(vector, top_k, index);
        }

        drop(index_guard);
        self.brute_force_search(vector, top_k)
    }

    fn brute_force_search(&self, query: &[f32], top_k: usize) -> Vec<SearchResult> {
        let vecs = self.vectors.read();
        let ids_guard = self.ids.read();
        let n = ids_guard.len();
        if n == 0 { return Vec::new(); }

        let mut heap = TopK::new(top_k);
        for i in 0..n {
            let dist = l2_distance_f32(query, &vecs[i * DIM..(i + 1) * DIM]);
            heap.push(dist, ids_guard[i]);
        }
        heap.into_results()
    }
}

#[inline(never)]
fn ivf_search(query: &[f32], top_k: usize, index: &IVFIndex) -> Vec<SearchResult> {
    // Step 1: Find nearest super-clusters (only 64 distance computations)
    let mut super_dists: Vec<(u8, f32)> = Vec::with_capacity(NUM_SUPER_CLUSTERS);
    for sc in 0..NUM_SUPER_CLUSTERS {
        let dist = l2_distance_f32(query, &index.super_centroids[sc * DIM..(sc + 1) * DIM]);
        super_dists.push((sc as u8, dist));
    }
    super_dists.select_nth_unstable_by(SUPER_NPROBE - 1, |a, b| a.1.partial_cmp(&b.1).unwrap());

    // Step 2: Within selected super-clusters, find nearest centroids
    // Collect candidate centroids from top super-clusters
    let mut candidate_centroids: Vec<(u16, f32)> = Vec::with_capacity(SUPER_NPROBE * (NUM_CLUSTERS / NUM_SUPER_CLUSTERS + 10));
    for i in 0..SUPER_NPROBE {
        let sc = super_dists[i].0 as usize;
        for &cid in &index.super_members[sc] {
            let dist = l2_distance_f32(query, &index.centroids[cid as usize * DIM..(cid as usize + 1) * DIM]);
            candidate_centroids.push((cid, dist));
        }
    }

    // Select top NPROBE from candidates
    let actual_nprobe = NPROBE.min(candidate_centroids.len());
    if actual_nprobe == 0 {
        return Vec::new();
    }
    candidate_centroids.select_nth_unstable_by(actual_nprobe - 1, |a, b| a.1.partial_cmp(&b.1).unwrap());

    let mut heap = TopK::new(top_k);

    for i in 0..actual_nprobe {
        let cluster_id = candidate_centroids[i].0 as usize;
        let cluster = &index.clusters[cluster_id];
        let count = cluster.ids.len();
        if count == 0 { continue; }

        let data = &cluster.data;
        let ids = &cluster.ids;

        for j in 0..count {
            let offset = j * DIM;
            let dist = l2_distance_f32(query, unsafe {
                data.get_unchecked(offset..offset + DIM)
            });
            if dist < heap.worst || heap.items.len() < heap.k {
                heap.push_unchecked(dist, unsafe { *ids.get_unchecked(j) });
            }
        }
    }

    heap.into_results()
}

struct TopK {
    items: Vec<(f32, u64)>,
    k: usize,
    worst: f32,
    worst_idx: usize,
}

impl TopK {
    #[inline]
    fn new(k: usize) -> Self {
        TopK {
            items: Vec::with_capacity(k),
            k,
            worst: f32::INFINITY,
            worst_idx: 0,
        }
    }

    #[inline(always)]
    fn push(&mut self, dist: f32, id: u64) {
        if self.items.len() < self.k {
            self.items.push((dist, id));
            if self.items.len() == self.k {
                self.recompute_worst();
            }
        } else if dist < self.worst {
            unsafe { *self.items.get_unchecked_mut(self.worst_idx) = (dist, id); }
            self.recompute_worst();
        }
    }

    #[inline(always)]
    fn push_unchecked(&mut self, dist: f32, id: u64) {
        if self.items.len() < self.k {
            self.items.push((dist, id));
            if self.items.len() == self.k {
                self.recompute_worst();
            }
        } else {
            unsafe { *self.items.get_unchecked_mut(self.worst_idx) = (dist, id); }
            self.recompute_worst();
        }
    }

    #[inline(always)]
    fn recompute_worst(&mut self) {
        let mut widx = 0;
        let mut wdist = unsafe { self.items.get_unchecked(0).0 };
        for i in 1..self.items.len() {
            let d = unsafe { self.items.get_unchecked(i).0 };
            if d > wdist {
                wdist = d;
                widx = i;
            }
        }
        self.worst = wdist;
        self.worst_idx = widx;
    }

    fn into_results(mut self) -> Vec<SearchResult> {
        self.items.sort_unstable_by(|a, b| a.0.partial_cmp(&b.0).unwrap());
        self.items.iter().map(|&(dist, id)| SearchResult {
            id,
            distance: dist as f64,
        }).collect()
    }
}

#[inline(always)]
fn find_nearest_centroid(vec: &[f32], centroids: &[f32], num_clusters: usize) -> usize {
    let mut best_idx = 0;
    let mut best_dist = f32::INFINITY;
    for c in 0..num_clusters {
        let dist = l2_distance_f32(vec, &centroids[c * DIM..(c + 1) * DIM]);
        if dist < best_dist {
            best_dist = dist;
            best_idx = c;
        }
    }
    best_idx
}

fn kmeans_clustering(vecs: &[f32], n: usize) -> Vec<f32> {
    let sample_size = n.min(KMEANS_SAMPLE_SIZE);
    let step = if sample_size < n { n / sample_size } else { 1 };

    let mut sample_data = vec![0.0f32; sample_size * DIM];
    for si in 0..sample_size {
        let idx = (si * step).min(n - 1);
        sample_data[si * DIM..(si + 1) * DIM].copy_from_slice(&vecs[idx * DIM..(idx + 1) * DIM]);
    }

    kmeans_local(&sample_data, sample_size, NUM_CLUSTERS, KMEANS_ITERS)
}

fn kmeans_local(data: &[f32], n: usize, num_clusters: usize, iters: usize) -> Vec<f32> {
    let actual_clusters = num_clusters.min(n);
    let mut centroids = vec![0.0f32; num_clusters * DIM];
    let centroid_step = (n / actual_clusters).max(1);
    for c in 0..actual_clusters {
        let src = (c * centroid_step).min(n - 1);
        centroids[c * DIM..(c + 1) * DIM].copy_from_slice(&data[src * DIM..(src + 1) * DIM]);
    }

    for _iter in 0..iters {
        // For large datasets use parallel, for small use sequential
        let assignments: Vec<usize> = if n > 10000 {
            (0..n).into_par_iter().map(|si| {
                find_nearest_centroid(&data[si * DIM..(si + 1) * DIM], &centroids, num_clusters)
            }).collect()
        } else {
            (0..n).map(|si| {
                find_nearest_centroid(&data[si * DIM..(si + 1) * DIM], &centroids, num_clusters)
            }).collect()
        };

        let mut new_centroids = vec![0.0f64; num_clusters * DIM];
        let mut counts = vec![0u32; num_clusters];

        for (si, &cluster_id) in assignments.iter().enumerate() {
            counts[cluster_id] += 1;
            let src_offset = si * DIM;
            for d in 0..DIM {
                new_centroids[cluster_id * DIM + d] += data[src_offset + d] as f64;
            }
        }

        for c in 0..num_clusters {
            if counts[c] > 0 {
                let inv = 1.0 / counts[c] as f64;
                for d in 0..DIM {
                    centroids[c * DIM + d] = (new_centroids[c * DIM + d] * inv) as f32;
                }
            }
        }
    }

    centroids
}
"}

