}

struct TopK {
    items: [(f32, u64); 16], // Fixed size, max top_k we'll see
    k: usize,
    len: usize,
    worst: f32,
    worst_idx: usize,
}

impl TopK {
    #[inline]
    fn new(k: usize) -> Self {
        debug_assert!(k <= 16);
        TopK {
            items: [(0.0, 0); 16],
            k,
            len: 0,
            worst: f32::INFINITY,
            worst_idx: 0,
        }
    }

    #[inline(always)]
    fn push(&mut self, dist: f32, id: u64) {
        if self.len < self.k {
            self.items[self.len] = (dist, id);
            self.len += 1;
            if self.len == self.k {
                self.recompute_worst();
            }
        } else if dist < self.worst {
            self.items[self.worst_idx] = (dist, id);
            self.recompute_worst();
        }
    }

    #[inline(always)]
    fn push_unchecked(&mut self, dist: f32, id: u64) {
